/**
 * CLI: read study graph snapshot JSON, exit 0 iff publish gate passes.
 */
import * as fs from 'node:fs';
import { evaluateStudyPublishGate } from '../src/study-publish-gate';

function main(): void {
  const path = process.argv[2];
  const raw =
    path === undefined || path === '-'
      ? fs.readFileSync(0, 'utf8')
      : fs.readFileSync(path, 'utf8');
  let json: unknown;
  try {
    json = JSON.parse(raw) as unknown;
  } catch {
    process.stderr.write('study-publish-gate: invalid JSON\n');
    process.exit(1);
  }
  const r = evaluateStudyPublishGate({ studyGraphSnapshot: json });
  if (!r.ok) {
    process.stderr.write(
      `study-publish-gate: blocked: ${r.reasons.join(', ')}\n`
    );
    process.exit(1);
  }
  process.stdout.write('study-publish-gate: ok\n');
  process.exit(0);
}

main();
